// Prepare multiple API calls for batching
const input = msg.payload;

// Create batch requests
msg.batchRequests = [
    {
        endpoint: 'get-soil-data',
        params: { county_fips: input.county_fips }
    },
    {
        endpoint: 'territorial-water-quality',
        params: { fips: input.county_fips }
    },
    {
        endpoint: 'live-agricultural-data',
        params: { 
            county_fips: input.county_fips,
            data_types: ['weather', 'soil_moisture'],
            forecast_days: 3
        }
    },
    {
        endpoint: 'carbon-credit-calculator',
        params: {
            county_fips: input.county_fips,
            acreage: input.acreage,
            crop_type: input.crop_type
        }
    }
];

// Store original input for later
msg.originalInput = input;
msg.batchCount = msg.batchRequests.length;

return msg;

// Create individual request messages from batch
const batchIndex = msg.index;
const batchRequest = msg.originalInput.batchRequests[batchIndex];

msg.endpoint = batchRequest.endpoint;
msg.payload = batchRequest.params;
msg.batchInfo = {
    index: batchIndex,
    total: msg.originalInput.batchCount,
    batchId: msg.originalInput.batchId || `batch_${Date.now()}`
};

return msg;

// Combine and analyze batch results
const results = msg.payload;
const input = msg.originalInput;

// Extract individual results
const soilData = results[`leafengines/get-soil-data`];
const waterData = results[`leafengines/territorial-water-quality`];
const weatherData = results[`leafengines/live-agricultural-data`];
const carbonData = results[`leafengines/carbon-credit-calculator`];

// Calculate field health score
let healthScore = 50; // Base score

if (soilData) {
    // Soil quality contributes 30%
    const soilScore = calculateSoilScore(soilData);
    healthScore += soilScore * 0.3;
}

if (waterData) {
    // Water quality contributes 25%
    const waterScore = calculateWaterScore(waterData);
    healthScore += waterScore * 0.25;
}

if (weatherData) {
    // Weather conditions contribute 20%
    const weatherScore = calculateWeatherScore(weatherData);
    healthScore += weatherScore * 0.2;
}

if (carbonData) {
    // Carbon potential contributes 25%
    const carbonScore = calculateCarbonScore(carbonData);
    healthScore += carbonScore * 0.25;
}

// Cap score at 100
healthScore = Math.min(100, Math.max(0, healthScore));

// Generate recommendations
const recommendations = [];

if (soilData && soilData.organic_matter < 2.0) {
    recommendations.push("Add organic matter to improve soil health");
}

if (waterData && waterData.water_quality_index < 70) {
    recommendations.push("Monitor water quality - consider filtration");
}

if (carbonData && carbonData.certification_eligible) {
    recommendations.push(`Eligible for carbon credits: $${carbonData.total_value.toFixed(2)} potential`);
}

// Prepare final output
msg.payload = {
    field_analysis: {
        county_fips: input.county_fips,
        crop_type: input.crop_type,
        acreage: input.acreage,
        health_score: Math.round(healthScore),
        health_category: getHealthCategory(healthScore),
        analysis_timestamp: new Date().toISOString()
    },
    data_sources: {
        soil: soilData ? 'available' : 'missing',
        water: waterData ? 'available' : 'missing',
        weather: weatherData ? 'available' : 'missing',
        carbon: carbonData ? 'available' : 'missing'
    },
    recommendations: recommendations,
    batch_optimization: {
        requests: input.batchCount,
        rate_limit_impact: "1 request (batched)",
        savings: `${Math.round((1 - 1/input.batchCount) * 100)}% reduction vs individual calls`
    }
};

// Add detailed data if available
if (soilData) msg.payload.detailed_soil = soilData;
if (waterData) msg.payload.detailed_water = waterData;
if (weatherData) msg.payload.detailed_weather = weatherData;
if (carbonData) msg.payload.detailed_carbon = carbonData;

msg.topic = "field/analysis";

return msg;

// Helper functions
function calculateSoilScore(soil) {
    let score = 50;
    if (soil.organic_matter >= 3.0) score += 20;
    else if (soil.organic_matter >= 2.0) score += 10;

    if (soil.ph_level >= 6.0 && soil.ph_level <= 7.5) score += 20;
    else if (soil.ph_level >= 5.5 && soil.ph_level <= 8.0) score += 10;

    return Math.min(100, score);
}

function calculateWaterScore(water) {
    let score = water.water_quality_index || 50;
    if (water.safety_status === 'safe') score += 20;
    return Math.min(100, score);
}

function calculateWeatherScore(weather) {
    let score = 50;
    if (weather.current_weather && !weather.current_weather.extreme_conditions) score += 30;
    if (weather.weather_forecast && weather.weather_forecast.favorable_days > 2) score += 20;
    return Math.min(100, score);
}

function calculateCarbonScore(carbon) {
    let score = 50;
    if (carbon.certification_eligible) score += 30;
    if (carbon.credit_value > 15) score += 20;
    return Math.min(100, score);
}

function getHealthCategory(score) {
    if (score >= 80) return 'Excellent';
    if (score >= 60) return 'Good';
    if (score >= 40) return 'Fair';
    return 'Needs Improvement';
}
